previewCss:
.darma-loader-darma-custom-456, .darma-loader-darma-custom-456:before, .darma-loader-darma-custom-456:after {
  width: 35px;
   aspect-ratio: 1;
   box-shadow: 0 0 0 3px inset currentColor;
   position: relative;
   animation: darma-loader-darma-custom-456-l6 1.5s infinite 0.5s;
}
.darma-loader-darma-custom-456:before, .darma-loader-darma-custom-456:after {
  content: "";
   position: absolute;
   left: calc(100% + 5px);
   animation-delay: 1s;
}
.darma-loader-darma-custom-456:after {
  left: -40px;
   animation-delay: 0s;
}
@keyframes darma-loader-darma-custom-456-l6  {
  0%,55%,100% {border-radius:0 }
20%,30% {border-radius:50%}
}

